class Solution:
    def minInsertions(self, s: str) -> int:
        insertions = 0
        available = 0
        for char in reversed(s):
            if char == ')':
                available += 1
            else:
                available -= 2
            if available < 0:
                insertions += (-available)
                available = 0
        return insertions
